def _parse_subject(subject: str) -> dict[str, Any]:
    parts = subject.split('/')
    if len(parts) != 3:
        raise ValueError(f"Invalid subject format: {subject}")
    role, department, level = parts
    return {'role': role, 'department': department, 'level': int(level)}

def _parse_resource(resource: str) -> dict[str, Any]:
    parts = resource.split(':')
    if len(parts) != 3:
        raise ValueError(f"Invalid resource format: {resource}")
    res_type, sensitivity, owner = parts
    return {'type': res_type, 'sensitivity': sensitivity, 'owner': owner}

def _evaluate_policy(subject: dict, resource: dict, action: str, policy: str) -> bool | None:
    """Return True if allow, False if deny, None if no match."""
    parts = policy.split()
    if len(parts) < 4:
        return None
    decision = parts[0].lower()  # "allow" or "deny"
    subj_pat = parts[1]
    act_pat = parts[2]
    res_pat = parts[3]

    # Subject pattern: role/department/level or wildcards
    subj_parts = subj_pat.split('/')
    if len(subj_parts) != 3:
        return None
    for i, key in enumerate(['role', 'department', 'level']):
        if subj_parts[i] != '*' and subj_parts[i] != subject[key]:
            return None

    # Action
    if act_pat != '*' and act_pat != action:
        return None

    # Resource pattern: type:sensitivity:owner
    res_parts = res_pat.split(':')
    if len(res_parts) != 3:
        return None
    for i, key in enumerate(['type', 'sensitivity', 'owner']):
        if res_parts[i] != '*' and res_parts[i] != resource[key]:
            return None

    return decision == 'allow'

def authorize(subject: str, resource: str, action: str, policies: list[str]) -> bool:
    subj_dict = _parse_subject(subject)
    res_dict = _parse_resource(resource)
    decision = None
    for policy in policies:
        result = _evaluate_policy(subj_dict, res_dict, action, policy)
        if result is not None:
            decision = result
    return decision if decision is not None else False

def audit_access(subject: str, resource: str, action: str, decision: bool) -> str:
    subj_dict = _parse_subject(subject)
    res_dict = _parse_resource(resource)
    verdict = "allowed" if decision else "denied"
