import re

_POLICY_PATTERN = re.compile(r"^(?P<condition>.+?)\s+(?P<effect>allow|deny)$")

def solve(policies: list[str]) -> str:
    parsed = []
    for p in policies:
        m = _POLICY_PATTERN.match(p)
        if m:
            parsed.append({
                "condition": m.group("condition").strip(),
                "effect": m.group("effect").strip()
            })
    # Sort so deny policies come first (deny = key 0, allow = key 1)
    parsed.sort(key=lambda x: 0 if x["effect"] == "deny" else 1)
    return parsed[0]["effect"] if parsed else ""
